73	// LoginState holds the short-lived in-memory authorization flow state.
74	type LoginState struct {
75		ServerName       string
76		RedirectURL      string
77		State            string
78		Verifier         string
79		AuthorizationURL string
80		Metadata         Metadata
81		Config           ServerConfig
82	}
83	
84	// BeginLogin discovers metadata, generates PKCE state, and returns the URL the
85	// operator must open. The returned verifier is sensitive and must stay in memory.
86	func (s *Service) BeginLogin(
87		ctx context.Context,
88		cfg ServerConfig,
89		redirectURL string,
90	) (LoginState, error) {
91		if err := cfg.Validate(); err != nil {
92			return LoginState{}, err
93		}
94		if err := validateAbsoluteHTTPURL("redirect URL", redirectURL); err != nil {
95			return LoginState{}, err
96		}
97	
98		metadata, err := discoverMetadata(ctx, s.client, cfg)
99		if err != nil {
100			return LoginState{}, err
101		}
102		if !supportsS256(metadata.CodeChallengeMethodsSupported) {
103			return LoginState{}, errors.New("mcp auth: OAuth server must support S256 PKCE")
104		}
105		pkce, err := newPKCEPair(s.random)
106		if err != nil {
107			return LoginState{}, err
108		}
109		if err := validateVerifier(pkce.Verifier); err != nil {
110			return LoginState{}, err
111		}
112		state, err := newState(s.random)
113		if err != nil {
114			return LoginState{}, err
115		}
116	
117		authURL, err := authorizationURL(metadata.AuthorizationEndpoint, cfg, redirectURL, state, pkce)
118		if err != nil {
119			return LoginState{}, err
120		}
121		return LoginState{
122			ServerName:       strings.TrimSpace(cfg.ServerName),
123			RedirectURL:      strings.TrimSpace(redirectURL),
124			State:            state,
125			Verifier:         pkce.Verifier,
126			AuthorizationURL: authURL,
127			Metadata:         metadata,
128			Config:           cfg,
129		}, nil
130	}
131	
132	// Exchange validates the OAuth callback and stores the token response.
133	func (s *Service) Exchange(ctx context.Context, state LoginState, callbackURL string) (Status, error) {
134		code, err := authorizationCodeFromCallback(callbackURL, state.State)
135		if err != nil {
136			return Status{}, err
137		}
138		if err := validateVerifier(state.Verifier); err != nil {
139			return Status{}, err
140		}
141	
142		token, err := s.exchangeCode(ctx, state, code)
143		if err != nil {
144			return Status{}, err
145		}
146		if err := s.store.SaveMCPAuthToken(ctx, token); err != nil {
147			return Status{}, fmt.Errorf("mcp auth: persist token for %q: %w", state.ServerName, err)
148		}
149		return statusFromToken(state.Config, &token, s.now()), nil
150	}
